import React, { useEffect, useState, useContext } from "react";
import axios from "axios";
import GeneralContext from "./GeneralContext";

const API_URL = process.env.REACT_APP_API_URL || "http://localhost:3002";

const FRONTEND_URL = process.env.REACT_APP_FRONTEND_URL || "http://localhost:3000";

const WatchList = () => {
  const [stocks, setStocks] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  const { openBuyWindow } = useContext(GeneralContext);

  // ==========================
  // Fetch Watchlist
  // ==========================
  useEffect(() => {
    const fetchWatchlist = async () => {
      try {
        const response = await axios.get(`${API_URL}/allWatchlist`);
        setStocks(Array.isArray(response.data) ? response.data : []);
      } catch (err) {
        console.error("Failed to fetch watchlist:", err);
        setError("Failed to load watchlist.");
      } finally {
        setLoading(false);
      }
    };

    fetchWatchlist();
  }, []);

  const formatCurrency = (value = 0) =>
    Number(value).toLocaleString("en-IN", {
      minimumFractionDigits: 2,
      maximumFractionDigits: 2,
    });

  if (loading) return <p>Loading watchlist...</p>;
  if (error) return <p className="error">{error}</p>;

  return (
    <>
      <div className="watchlist-header" style={{ display: 'flex', flexDirection: 'column', alignItems: 'flex-start', gap: '15px' }}>
        <img src="http://localhost:3002/new_logo.png" alt="Wave Logo" style={{ width: '120px' }} />
        <div style={{ display: 'flex', alignItems: 'center', gap: '10px', width: '100%' }}>
          <a href={FRONTEND_URL} className="back-home-btn" id="back-home-button" title="Back to Home">
            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
              <line x1="19" y1="12" x2="5" y2="12" />
              <polyline points="12 19 5 12 12 5" />
            </svg>
          </a>
          <h3 className="title" style={{ margin: 0 }}>Watchlist ({stocks.length})</h3>
        </div>
      </div>

      <div className="order-table">
        <table>
          <thead>
            <tr>
              <th>Stock</th>
              <th>Price</th>
              <th>Change</th>
            </tr>
          </thead>

          <tbody>
            {stocks.map((stock, index) => {
              const price = stock.price || 0;
              const percent = stock.percent || "0%";
              const isDown = stock.isDown;

              return (
                <tr
                  key={stock._id || `${stock.name}-${index}`}
                  style={{ cursor: "pointer" }}
                  onClick={() =>
                    openBuyWindow({
                      name: stock.name,
                      price: price,
                    })
                  }
                >
                  <td>{stock.name}</td>
                  <td>₹{formatCurrency(price)}</td>
                  <td className={isDown ? "loss" : "profit"}>
                    {percent}
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </>
  );
};

export default WatchList;
